avg by (provider, source_region) (
  quantile_over_time(0.95, 
    (response_latency_seconds{metric_type="response_time", blockchain="Arbitrum", response_status="success", source_region=~"fra1|sfo1|hnd1"} >= 0)[$__range:$__interval]
  )
)

avg by (provider, api_method) (
  quantile_over_time(0.95, 
    (response_latency_seconds{metric_type="response_time", blockchain="Arbitrum", response_status="success"} >= 0)[$__range:$__interval]
  )
)

avg by (provider, api_method, source_region) (
  quantile_over_time(0.95, 
    (
      response_latency_seconds{metric_type="response_time", blockchain="Arbitrum", response_status="success", api_method=~"(eth_call|eth_getBalance)", source_region=~"fra1|sfo1|hnd1"} 
      >= 0
    )[$__range:$__interval]
