avg by (provider, api_method, source_region) (
  quantile_over_time(0.95, 
    (response_latency_seconds{metric_type="response_time", blockchain="Arbitrum", response_status="success", api_method=~"(.*debug.*|eth_subscribe)", source_region=~"fra1|sfo1|hnd1"} >= 0)[$__range:$__interval]
  )
)

min by (provider) (
  (
    group by (provider, source_region, block_number, value) (
      response_latency_seconds{metric_type="balance_observed", blockchain="Arbitrum"}
    )
    *
    on(source_region, block_number, value) group_left()
    count by (source_region, block_number, value) (
      response_latency_seconds{metric_type="balance_observed", blockchain="Arbitrum"}
    )
  )
  ==
  bool on(source_region, block_number) group_left()
  max by (source_region, block_number) (
    count by (source_region, block_number, value) (
      response_latency_seconds{metric_type="balance_observed", blockchain="Arbitrum"}
    )
  )
)

sum by (provider, source_region) (
  max_over_time(
    (
      (
        group by (provider, source_region, block_number, value) (
          response_latency_seconds{metric_type="balance_observed", blockchain="Arbitrum"}
        )
        *
        on(source_region, block_number, value) group_left()
        count by (source_region, block_number, value) (
          response_latency_seconds{metric_type="balance_observed", blockchain="Arbitrum"}
        )
      )
      ==
      bool on(source_region, block_number) group_left()
      max by (source_region, block_number) (
        count by (source_region, block_number, value) (
          response_latency_seconds{metric_type="balance_observed", blockchain="Arbitrum"}
        )
      )
    )[$__range:1m]
  ) > bool 0
)
/
sum by (provider, source_region) (
  max_over_time(
    (
      group by (provider, source_region, block_number, value) (
        response_latency_seconds{metric_type="balance_observed", blockchain="Arbitrum"}
